// UpdateAccountRiskConfig is the resolver for the UpdateAccountRiskConfig field.
func (r *mutationResolver) UpdateAccountRiskConfig(ctx context.Context, input model.UpdateAccountRiskConfigInput) (*model.Account, error) {
	_, ok := auth.GetUserFromContext(ctx)
	if !ok {
		return nil, mowerror.New(mowerror.PermissionDenied, "unauthorized")
	}
	accountID := strings.TrimSpace(input.AccountID)
	if accountID == "" {
		return nil, mowerror.New(mowerror.InvalidArgument, "accountId is required")
	}

	toAmountLimit := func(src *model.AmountLimitInput) *ctypes.AmountLimitStrings {
		if src == nil {
			return nil
		}
		amount := lo.FromPtr(src.Amount)
		ratio := lo.FromPtr(src.Ratio)
		if strings.TrimSpace(amount) == "" && strings.TrimSpace(ratio) == "" {
			return nil
		}
		return &ctypes.AmountLimitStrings{Amount: amount, Ratio: ratio}
	}

	resp, err := r.AccountSvc.UpdateAccountRiskConfig(ctx, &ctypes.UpdateAccountRiskConfigRequest{
		AccountID:                 accountID,
		MaxOrderSize:              lo.FromPtr(input.MaxOrderSize),
		MaxLeverage:               lo.FromPtr(input.MaxLeverage),
		MaxOrdersPerMinute:        int32(lo.FromPtrOr(input.MaxOrdersPerMinute, 0)),
		MinMaintenanceMarginRatio: lo.FromPtr(input.MinMaintenanceMarginRatio),
		RiskIndexThreshold:        lo.FromPtr(input.RiskIndexThreshold),
		RiskIndexAction:           lo.FromPtr(input.RiskIndexAction),
		CooldownSeconds:           int32(lo.FromPtrOr(input.CooldownSeconds, 0)),
		MaxPositionPerSymbol:      toAmountLimit(input.MaxPositionPerSymbol),
		MaxDailyLoss:              toAmountLimit(input.MaxDailyLoss),
		MaxTotalNetExposure:       toAmountLimit(input.MaxTotalNetExposure),
		MaxTotalGrossExposure:     toAmountLimit(input.MaxTotalGrossExposure),
	})
	if err != nil {
		return nil, err
	}
	if resp == nil || resp.Account == nil {
		return nil, mowerror.New(mowerror.Internal, "empty response")
	}
	return converter.AccountTypes2Gql(resp.Account), nil
}

