// Equitys is the resolver for the Equitys field.
func (r *queryResolver) Equitys(ctx context.Context, input model.QueryEquitysInput) ([]*model.Equity, error) {
	_, ok := auth.GetUserFromContext(ctx)
	if !ok {
		return nil, mowerror.New(mowerror.PermissionDenied, "unauthorized")
	}
	if input.AccountID == "" {
		return nil, mowerror.New(mowerror.InvalidArgument, "accountId is required")
	}
	rangeKey := strings.ToLower(strings.TrimSpace(input.Range))
	duration := 7 * 24 * time.Hour
	switch rangeKey {
	case "1d", "1day", "day":
		duration = 24 * time.Hour
	case "7d", "1w", "week", "7day":
		duration = 7 * 24 * time.Hour
	case "30d", "1m", "month", "30day":
		duration = 30 * 24 * time.Hour
	}
	endTs := time.Now()
	startTs := endTs.Add(-duration)

	response, err := r.AccountSvc.QueryEquitys(ctx, &ctypes.QueryEquitysRequest{
		AccountID: input.AccountID,
		StartTs:   startTs.UnixMilli(),
		EndTs:     endTs.UnixMilli(),
	})
	if err != nil {
		return nil, err
	}
	if response == nil || len(response.Equitys) == 0 {
		return []*model.Equity{}, nil
	}
	result := make([]*model.Equity, 0, len(response.Equitys))
	for _, item := range response.Equitys {
		if item == nil {
			continue
		}
		if ge := converter.EquityTypes2Gql(item); ge != nil {
			result = append(result, ge)
		}
	}
	return result, nil
}

// AccountEventFlow is the resolver for the AccountEventFlow field.
func (r *queryResolver) AccountEventFlow(ctx context.Context, input model.QueryAccountEventFlowInput) (*model.AccountEventFlowConnection, error) {
	_, ok := auth.GetUserFromContext(ctx)
	if !ok {
		return nil, mowerror.New(mowerror.PermissionDenied, "unauthorized")
	}
	if input.AccountID == "" {
		return nil, mowerror.New(mowerror.InvalidArgument, "accountId is required")
	}

	stream := converter.EventFlowStreamGql2Types(input.Stream)
	if stream == ctypes.EventFlowStreamUnspecified {
		stream = ctypes.EventFlowStreamAll
	}

	limit := int32(100)
	if input.Limit != nil && *input.Limit > 0 {
		limit = int32(*input.Limit)
	}

	var startID *int64
	if input.StartID != nil {
		startID = lo.ToPtr(int64(*input.StartID))
	}

	response, err := r.AccountSvc.QueryAccountEventFlow(ctx, &ctypes.QueryAccountEventFlowRequest{
		AccountID: input.AccountID,
		Stream:    stream,
		StartTsMs: types.PIntToPInt64(input.StartTsMs),
		StartID:   startID,
		Limit:     limit,
	})
	if err != nil {
		return nil, err
	}

	events := make([]*model.EventRecord, 0, len(response.Events))
	for _, evt := range response.Events {
		if evt == nil {
			continue
		}
		events = append(events, &model.EventRecord{
			ID:          strconv.FormatInt(evt.ID, 10),
			AccountID:   evt.AccountID,
			Exchange:    evt.Exchange,
			Stream:      evt.Stream,
			Topic:       evt.Topic,
			EventKind:   evt.EventKind,
			TsMs:        int(evt.TsMs),
			ReceiveAtMs: int(evt.ReceiveAtMs),
			PublishAtMs: int(evt.PublishAtMs),
			IngestAtMs:  int(evt.IngestAtMs),
			PayloadJSON: evt.PayloadJSON,
		})
	}

	return &model.AccountEventFlowConnection{
		Events: events,
		NextID: strconv.FormatInt(response.NextID, 10),
	}, nil
}

